  ('social-worker-moex-06380', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關家庭生命週期理論，下列那一項陳述不符合該理論的主張？ 每個家庭一定都會經歷依序性的家庭生命週期階段，並發展類似的家庭任務 接受代間角色的轉移是「子女離巢」生命階段之任務 未預期的家庭事件會影響家庭生命週期階段的移轉，例如離婚、喪偶、延後生育等 生命週期和婚姻滿意度呈U字形關係，其中有學齡子女家庭階段的婚姻滿意度最低', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06381', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '從環境、過去經驗和其他心理活動（例如：計畫和策略）當中，取得、組織和運用感官與知覺之訊息的 過程，稱之為？ 覺知  知覺  認知  資訊處理', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06382', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關女性更年期，下列那一項定義是正確的？ 女性的月經週期變得不規則  女性因年齡而無法懷孕 女性月經週期停止運作已超過一年  女性連續錯過三次定期的月經', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06383', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於老人虐待事件，下列敘述何者錯誤？ 老人虐待包括身體虐待、性虐待、經濟剝削等 施虐者以成年子女、家庭成員、配偶居多 家庭成員有藥癮、酒癮、精神病者較易成為施虐者 老人被遺棄，不包括在老人虐待的定義範圍內', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06384', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那項論述不是佛洛伊德（Frend）的主張？ 他主張原慾的驅力和對此驅力的壓抑都會影響人類的行為 他主張同性戀的人格是不可能發展出來的 他主張人格的形成是由一系列發展階段累積而成的 他主張兒童早期的發展對於個人日後的人格具有關鍵性的影響', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06385', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一種理論主張幼兒期及青少年的行為通常是由觀察和模仿別人的行為而來？ 心理動力論  社會學習理論  行為理論  成熟理論', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06386', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關青少年自尊心的研究發現，何者錯誤？ 青少年的自尊心在國中階段最低  多數青少年的自尊心在青春期會顯著改變 青少年的自尊心與短期達成目標的能力有關  青少年的自尊心在青春期沒有巨大改變', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06387', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在發展的階段中，主張個人會透過「自我肯定或漠不關心」找到自己在這個世界裡的位置，提倡此理論 的學者是誰？ 佛洛伊德  艾瑞克森  皮亞傑  柯伯格', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06388', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關生態系統理論，下列敍述何者錯誤？ 生態系統關心生物實體與其環境其他系統彼此之互動關係 生態系統提出微視、中介、外在與鉅視等環境系統 生態系統以生態圖來預估解析案主的問題 生態系統主張要降低案主早年生活經驗對當前社會生活之影響，增強自我功能和人際互動模式', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06389', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關安寧照顧的理念，下列敘述何者錯誤？ 以照顧為主，尊重生命尊嚴與品質 以治療為主，病患痊癒為目標 是全人照顧，包括身體的、心理社會與靈性的關懷 強調共同決策，而不是醫療專業控制醫療決策', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
